// /frontend/src/components/SearchSection.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";

export default function SearchSection({
  className = "",
  placeholder = "Search any city…",
  defaultValue = "",
  onSelect = () => {},
}) {
  const [q, setQ] = useState(defaultValue);
  const [results, setResults] = useState([]);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");
  const [active, setActive] = useState(0);
  const boxRef = useRef(null);

  // Debounce the query
  const debouncedQ = useDebounce(q, 250);

  useEffect(() => {
    let abort = new AbortController();
    async function run() {
      setErr("");
      if (!debouncedQ || debouncedQ.trim().length < 2) {
        setResults([]);
        return;
      }
      setLoading(true);
      try {
        // Nominatim free global geocoder (JSON v2)
        // NOTE: Be gentle with rate limits. We debounce above.
        const url = new URL("https://nominatim.openstreetmap.org/search");
        url.searchParams.set("format", "jsonv2");
        url.searchParams.set("addressdetails", "1");
        url.searchParams.set("limit", "8");
        url.searchParams.set("q", debouncedQ.trim());

        const res = await fetch(url.toString(), {
          signal: abort.signal,
          headers: {
            "Accept-Language": "en",
            // Nominatim asks for an identifiable UA; browsers lock UA headers,
            // but Referer will include your site. For heavy use, consider your own proxy.
          },
        });
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = await res.json();

        const mapped = (Array.isArray(data) ? data : []).map((d) => ({
          display: d.display_name,
          lat: parseFloat(d.lat),
          lon: parseFloat(d.lon),
          city:
            d.address?.city ||
            d.address?.town ||
            d.address?.village ||
            d.address?.hamlet ||
            d.address?.municipality ||
            "",
          state: d.address?.state || d.address?.region || "",
          country: d.address?.country || "",
        }));
        setResults(mapped);
        setOpen(true);
        setActive(0);
      } catch (e) {
        if (e.name !== "AbortError") {
          setErr("Search failed. Try again.");
          setResults([]);
        }
      } finally {
        setLoading(false);
      }
    }
    run();
    return () => abort.abort();
  }, [debouncedQ]);

  // Close dropdown on outside click
  useEffect(() => {
    function onDocClick(e) {
      if (!boxRef.current?.contains(e.target)) setOpen(false);
    }
    document.addEventListener("mousedown", onDocClick);
    return () => document.removeEventListener("mousedown", onDocClick);
  }, []);

  function choose(idx) {
    const item = results[idx];
    if (!item) return;
    setQ(item.display);
    setOpen(false);
    onSelect(item); // {display, lat, lon, city, state, country}
  }

  function onKeyDown(e) {
    if (!open && (e.key === "ArrowDown" || e.key === "Enter")) {
      setOpen(true);
      return;
    }
    if (e.key === "ArrowDown") {
      e.preventDefault();
      setActive((i) => Math.min(i + 1, Math.max(0, results.length - 1)));
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      setActive((i) => Math.max(i - 1, 0));
    } else if (e.key === "Enter") {
      e.preventDefault();
      if (results.length > 0) choose(active);
    } else if (e.key === "Escape") {
      setOpen(false);
    }
  }

  return (
    <div ref={boxRef} className={`relative w-full ${className}`}>
      <input
        value={q}
        onChange={(e) => setQ(e.target.value)}
        onFocus={() => results.length && setOpen(true)}
        onKeyDown={onKeyDown}
        placeholder={placeholder}
        className="w-full px-4 py-3 rounded-xl bg-black/60 text-white placeholder-gray-300 outline-none ring-1 ring-white/10 focus:ring-purple-500"
        aria-autocomplete="list"
        aria-expanded={open}
        aria-controls="search-suggest"
      />
      {open && (
        <div
          id="search-suggest"
          className="absolute z-50 mt-2 w-full max-h-72 overflow-auto rounded-xl backdrop-blur-md bg-black/70 ring-1 ring-white/10"
        >
          {loading && (
            <div className="px-4 py-3 text-sm text-gray-200">Searching…</div>
          )}
          {!loading && err && (
            <div className="px-4 py-3 text-sm text-red-300">{err}</div>
          )}
          {!loading && !err && results.length === 0 && debouncedQ.length >= 2 && (
            <div className="px-4 py-3 text-sm text-gray-200">No matches.</div>
          )}
          {!loading &&
            results.map((r, i) => (
              <button
                key={`${r.lat},${r.lon},${i}`}
                onClick={() => choose(i)}
                className={`w-full text-left px-4 py-3 text-sm text-white hover:bg-white/10 ${
                  i === active ? "bg-white/10" : ""
                }`}
              >
                <div className="font-medium">
                  {r.city || r.display.split(",")[0]}
                </div>
                <div className="text-xs text-gray-300">
                  {r.state ? `${r.state}, ` : ""}
                  {r.country}
                </div>
              </button>
            ))}
        </div>
      )}
    </div>
  );
}

// simple debounce hook
function useDebounce(value, ms = 250) {
  const [v, setV] = useState(value);
  useEffect(() => {
    const id = setTimeout(() => setV(value), ms);
    return () => clearTimeout(id);
  }, [value, ms]);
  return v;
}
